  bool _isInitialized = false;

  Future<void> initialize() async {
    if (_isInitialized) return;
    _prefs = await SharedPreferences.getInstance();
    await _loadStoredAuth();
    _isInitialized = true;
  }

  Future<void> _loadStoredAuth() async {
    final isLoggedIn = _prefs?.getBool(_isLoggedInKey) ?? false;
    if (!isLoggedIn) {
      _authStateController.add(AuthState.unauthenticated);
      return;
    }

    final tokenJson = _prefs?.getString(_authTokenKey);
    final userJson = _prefs?.getString(_userDataKey);

    if (tokenJson != null && userJson != null) {
      try {
        _currentToken = AuthToken.fromJson(json.decode(tokenJson));
        _currentUser = UserData.fromJson(json.decode(userJson));

        if (_currentToken!.isExpired) {
