      await _prefs?.setString(_userDataKey, json.encode(_currentUser!.toJson()));
      await _prefs?.setBool(_isLoggedInKey, true);
      await _prefs?.setInt(_loginTimestampKey, DateTime.now().millisecondsSinceEpoch);

