    _currentToken = null;
    _currentUser = null;

    await _prefs?.remove(_authTokenKey);
    await _prefs?.remove(_userDataKey);
    await _prefs?.setBool(_isLoggedInKey, false);
    await _prefs?.remove(_loginTimestampKey);

    _authStateController.add(AuthState.unauthenticated);
  }

