class AuthGuard extends StatefulWidget {
  final Widget authenticatedWidget;
  final Widget unauthenticatedWidget;

  const AuthGuard({
    Key? key,
    required this.authenticatedWidget,
    required this.unauthenticatedWidget,
  }) : super(key: key);

  @override
  State<AuthGuard> createState() => _AuthGuardState();
}

class _AuthGuardState extends State<AuthGuard> {
  final AuthenticationManager _authManager = AuthenticationManager();
  StreamSubscription<AuthState>? _authSubscription;
  AuthState _currentState = AuthState.unauthenticated;

  @override
  void initState() {
    super.initState();
    _initializeAuth();
  }

  Future<void> _initializeAuth() async {
    await _authManager.initialize();
    setState(() {
      _currentState = _authManager.isAuthenticated
          ? AuthState.authenticated
          : AuthState.unauthenticated;
    });

    _authSubscription = _authManager.authStateStream.listen((state) {
      setState(() {
        _currentState = state;
      });
    });
  }

  @override
  void dispose() {
    _authSubscription?.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return _currentState == AuthState.authenticated
        ? widget.authenticatedWidget
        : widget.unauthenticatedWidget;
  }
}

